public class MYCLASS {
  private static final java.util.logging.Logger LOG = java.util.logging.Logger.getLogger(MYCLASS.class.getName());
  private String id;

  // Returns the current object id as a string; if cancreate is true, creates a new id when missing
  public String readObjectID() {
    return id;
  }

  public String createObjectID() {
    if (id == null) {
      id = generateID();
      LOG.fine("Created new object ID: " + id);
    }
    return id;
  }

  public String generateID() {
    return java.util.UUID.randomUUID().toString();
  }

  @Override
  public String toString() {
    return id;
  }

  // Optional helper to get id with a creation policy
  public String getId(boolean cancreate) {
    if (id != null) {
      return id;
    }
    if (cancreate) {
      return createObjectID();
    }
    return null;
  }
}
